import api from './api';

export const getAlbums = () => api.get('/albums');
export const getAlbum = (id) => api.get(`/albums/${id}`);
export const createAlbum = (data) => api.post('/albums', data);
export const createAlbumWithImage = (formData) => api.post('/albums/create', formData, { headers: { 'Content-Type': 'multipart/form-data' } });
export const updateAlbum = (id, data) => api.put(`/albums/${id}`, data);
export const updateAlbumWithImage = (id, formData) => api.put(`/albums/${id}`, formData, { headers: { 'Content-Type': 'multipart/form-data' } });
export const deleteAlbum = (id) => api.delete(`/albums/${id}`);
